void solve(int CASE)
{
	int n; cin >> n;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}
	LCA lca(n, g);

	int q; cin >> q;
	while (q--) {
		int m; cin >> m;
		var tmp = vector<int>();
		fa(i, 1, m) {
			int x; cin >> x;
			tmp.pb(x);
		}

		if (m == 1) {
			cout << "YES" << endl;
			continue;
		}

		// 找深度最大的端点 u
		int mxdep = 0, u = 0; 
		for (int x : tmp) {
			if (mxdep < lca.depth[x]) {
				mxdep = lca.depth[x];
				u = x;
			}
		}

		// 找离 u 最远的端点 v
		int dis = 0, v = 0;
		for (int x : tmp) {
			int now = lca.dis(x, u);
			if (dis < now) {
				dis = now;
				v = x;
			}
		}

		// 重要的公式判断
		bool ok = 1;
		for (int x : tmp) {
			if (lca.dis(u, x) + lca.dis(x, v) != lca.dis(u, v)) {
				ok = 0;
				break;
			}
		}

		if (ok)cout << "YES" << endl;
		else cout << "NO" << endl;
	}
	return;
}
